const products = $('Get WooCommerce Products').all().map((item) => item.json);
const existingRows = $('Get Existing Sheet Rows').all().map((item) => item.json);

// Map existing sheet rows by ID (as string) for O(1) lookup. Empty IDs are
// filtered so that an empty sheet on the first run does not create a
// phantom entry.
const existingRowsById = new Map();
for (const row of existingRows) {
  const id = String(row.ID);
  if (id && id !== 'undefined') {
    existingRowsById.set(id, row);
  }
}

const syncedAt = new Date().toISOString();
const results = [];

for (const product of products) {
  const id = String(product.id);
  const name = product.name;
  const price = String(product.price);
  const image = product.images && product.images.length > 0 ? product.images[0].src : '';

  const existingRow = existingRowsById.get(id);

  // Not in the sheet yet -> new product.
  if (!existingRow) {
    results.push({
      json: {
        ID: product.id,
        Producto: name,
        Precio: price,
        Imagen: image,
        Sincronizado: syncedAt,
        accion: 'alta',
        detalle: '',
      },
    });
    continue;
  }

  // Already in the sheet -> compare as strings, since Google Sheets always
  // returns text values regardless of the original WooCommerce type.
  const existingName = existingRow.Producto !== undefined ? String(existingRow.Producto) : '';
  const existingPrice = existingRow.Precio !== undefined ? String(existingRow.Precio) : '';
  const existingImage = existingRow.Imagen !== undefined ? String(existingRow.Imagen) : '';

  const changes = [];
  if (existingName !== name) {
    changes.push(`Producto "${existingName}" → "${name}"`);
  }
  if (existingPrice !== price) {
    changes.push(`Precio $${existingPrice} → $${price}`);
  }
  if (existingImage !== image) {
    changes.push('Imagen actualizada');
  }

  // Nothing tracked changed -> discard, do not touch the sheet or the email.
  if (changes.length === 0) {
    continue;
  }

  results.push({
    json: {
      ID: product.id,
      Producto: name,
      Precio: price,
      Imagen: image,
      Sincronizado: syncedAt,
      accion: 'cambio',
      detalle: changes.join('; '),
    },
  });
}

return results;

// Group the classified items into "alta" (new) and "cambio" (updated), and
// pre-format the subject/body pieces here so the email node only has to
// interpolate ready-made strings.
const items = $('Classify Products').all().map((item) => item.json);

const nuevos = items.filter((item) => item.accion === 'alta');
const actualizados = items.filter((item) => item.accion === 'cambio');

const subjectParts = [];
if (nuevos.length > 0) {
  subjectParts.push(`${nuevos.length} nuevo${nuevos.length === 1 ? '' : 's'}`);
}
if (actualizados.length > 0) {
  subjectParts.push(`${actualizados.length} actualizado${actualizados.length === 1 ? '' : 's'}`);
}

const bodySections = [];
if (nuevos.length > 0) {
  const lines = nuevos.map((item) => `- ID ${item.ID}: ${item.Producto} (precio: ${item.Precio})`);
  bodySections.push(`Nuevos:\n${lines.join('\n')}`);
}
if (actualizados.length > 0) {
  const lines = actualizados.map((item) => `- ID ${item.ID}: ${item.Producto} — ${item.detalle}`);
  bodySections.push(`Actualizados:\n${lines.join('\n')}`);
}

return [
  {
    json: {
      countNuevos: nuevos.length,
      countActualizados: actualizados.length,
      subjectSummary: subjectParts.join(', '),
      bodySummary: bodySections.join('\n\n'),
    },
  },
];

